import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useSocket } from '../../contexts/SocketContext';
import {
  ChartBarIcon,
  ShoppingBagIcon,
  ArrowPathIcon,
  ChatBubbleLeftIcon,
  StarIcon,
  ExclamationTriangleIcon,
  Battery100Icon,
  SunIcon
} from '@heroicons/react/24/outline';
import {
  LineChart,
  Line,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell
} from 'recharts';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const AdminDashboard = () => {
  const { sensorData, alerts } = useSocket();
  const [dashboardData, setDashboardData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [salesData, setSalesData] = useState([]);

  useEffect(() => {
    fetchDashboardData();
    fetchSalesReport();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await axios.get(`${API_URL}/admin/dashboard`);
      setDashboardData(response.data);
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchSalesReport = async () => {
    try {
      const response = await axios.get(`${API_URL}/transactions/report`);
      const data = response.data;
      
      // Convert daily data to chart format
      const chartData = Object.keys(data.daily_data).map(date => ({
        date,
        sales: data.daily_data[date].sales,
        kg: data.daily_data[date].kg
      }));
      
      setSalesData(chartData.slice(-7)); // Last 7 days
    } catch (error) {
      console.error('Error fetching sales report:', error);
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-green-600"></div>
      </div>
    );
  }

  const COLORS = ['#10B981', '#F59E0B', '#EF4444', '#3B82F6', '#8B5CF6'];

  return (
    <div>
      <h1 className="text-2xl font-semibold text-gray-900 mb-6">Admin Dashboard</h1>

      {/* Real-time Sensor Status */}
      {sensorData && (
        <div className="bg-white shadow rounded-lg p-6 mb-6">
          <h2 className="text-lg font-medium text-gray-900 mb-4">Machine Status</h2>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div className="bg-green-50 rounded-lg p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-green-600 font-medium">Sinandomeng</p>
                  <p className="text-2xl font-bold text-gray-900">{sensorData.container_1_level?.toFixed(1)} kg</p>
                </div>
                <span className={`px-2 py-1 text-xs font-semibold rounded-full ${
                  sensorData.container_1_stock === 'OK' ? 'bg-green-100 text-green-800' :
                  sensorData.container_1_stock === 'LOW' ? 'bg-yellow-100 text-yellow-800' :
                  'bg-red-100 text-red-800'
                }`}>
                  {sensorData.container_1_stock}
                </span>
              </div>
            </div>
            
            <div className="bg-blue-50 rounded-lg p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-blue-600 font-medium">Dinorado</p>
                  <p className="text-2xl font-bold text-gray-900">{sensorData.container_2_level?.toFixed(1)} kg</p>
                </div>
                <span className={`px-2 py-1 text-xs font-semibold rounded-full ${
                  sensorData.container_2_stock === 'OK' ? 'bg-green-100 text-green-800' :
                  sensorData.container_2_stock === 'LOW' ? 'bg-yellow-100 text-yellow-800' :
                  'bg-red-100 text-red-800'
                }`}>
                  {sensorData.container_2_stock}
                </span>
              </div>
            </div>
            
            <div className="bg-yellow-50 rounded-lg p-4">
              <div className="flex items-center">
                <Battery100Icon className="h-8 w-8 text-yellow-600 mr-3" />
                <div>
                  <p className="text-sm text-yellow-600 font-medium">Battery</p>
                  <p className="text-2xl font-bold text-gray-900">{sensorData.battery_percentage?.toFixed(1)}%</p>
                  <p className="text-xs text-gray-500">{sensorData.battery_voltage?.toFixed(1)}V</p>
                </div>
              </div>
            </div>
            
            <div className="bg-purple-50 rounded-lg p-4">
              <div className="flex items-center">
                <SunIcon className="h-8 w-8 text-purple-600 mr-3" />
                <div>
                  <p className="text-sm text-purple-600 font-medium">Solar</p>
                  <p className="text-sm font-semibold text-gray-900">{sensorData.solar_panel_voltage?.toFixed(1)}V</p>
                  <p className="text-xs text-gray-500">{sensorData.solar_charging ? 'Charging' : 'Not Charging'}</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Stats Grid */}
      <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-4 mb-6">
        <div className="bg-white overflow-hidden shadow rounded-lg">
          <div className="p-5">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-green-100 rounded-md p-3">
                <ShoppingBagIcon className="h-6 w-6 text-green-600" />
              </div>
              <div className="ml-5 w-0 flex-1">
                <dl>
                  <dt className="text-sm font-medium text-gray-500 truncate">Today's Sales</dt>
                  <dd className="text-lg font-medium text-gray-900">₱{dashboardData?.today_sales?.toFixed(2) || '0.00'}</dd>
                  <dd className="text-sm text-gray-500">{dashboardData?.today_kg?.toFixed(1) || '0'} kg</dd>
                </dl>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white overflow-hidden shadow rounded-lg">
          <div className="p-5">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-yellow-100 rounded-md p-3">
                <ArrowPathIcon className="h-6 w-6 text-yellow-600" />
              </div>
              <div className="ml-5 w-0 flex-1">
                <dl>
                  <dt className="text-sm font-medium text-gray-500 truncate">Pending Returns</dt>
                  <dd className="text-lg font-medium text-gray-900">{dashboardData?.pending_returns || 0}</dd>
                </dl>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white overflow-hidden shadow rounded-lg">
          <div className="p-5">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-blue-100 rounded-md p-3">
                <ChatBubbleLeftIcon className="h-6 w-6 text-blue-600" />
              </div>
              <div className="ml-5 w-0 flex-1">
                <dl>
                  <dt className="text-sm font-medium text-gray-500 truncate">Unread Messages</dt>
                  <dd className="text-lg font-medium text-gray-900">{dashboardData?.unread_messages || 0}</dd>
                </dl>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white overflow-hidden shadow rounded-lg">
          <div className="p-5">
            <div className="flex items-center">
              <div className="flex-shrink-0 bg-purple-100 rounded-md p-3">
                <ExclamationTriangleIcon className="h-6 w-6 text-purple-600" />
              </div>
              <div className="ml-5 w-0 flex-1">
                <dl>
                  <dt className="text-sm font-medium text-gray-500 truncate">Low Stock Alerts</dt>
                  <dd className="text-lg font-medium text-gray-900">{dashboardData?.low_stock_alerts?.length || 0}</dd>
                </dl>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        {/* Sales Chart */}
        <div className="bg-white shadow rounded-lg p-6">
          <h2 className="text-lg font-medium text-gray-900 mb-4">Sales (Last 7 Days)</h2>
          <ResponsiveContainer width="100%" height={300}>
            <LineChart data={salesData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="date" />
              <YAxis yAxisId="left" />
              <YAxis yAxisId="right" orientation="right" />
              <Tooltip />
              <Legend />
              <Line yAxisId="left" type="monotone" dataKey="sales" stroke="#10B981" name="Sales (₱)" />
              <Line yAxisId="right" type="monotone" dataKey="kg" stroke="#F59E0B" name="Quantity (kg)" />
            </LineChart>
          </ResponsiveContainer>
        </div>

        {/* Recent Transactions */}
        <div className="bg-white shadow rounded-lg p-6">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-medium text-gray-900">Recent Transactions</h2>
            <Link to="/admin/transactions" className="text-sm text-green-600 hover:text-green-800">View all</Link>
          </div>
          <div className="space-y-3">
            {dashboardData?.recent_transactions?.map((transaction) => (
              <div key={transaction.id} className="flex justify-between items-center p-3 bg-gray-50 rounded-lg">
                <div>
                  <p className="text-sm font-medium text-gray-900">{transaction.rice_type}</p>
                  <p className="text-xs text-gray-500">{transaction.quantity_kg} kg • {new Date(transaction.timestamp).toLocaleTimeString()}</p>
                </div>
                <div className="text-right">
                  <p className="text-sm font-semibold text-gray-900">₱{transaction.amount_paid}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Returns and Alerts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Pending Returns */}
        <div className="bg-white shadow rounded-lg p-6">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-medium text-gray-900">Pending Returns</h2>
            <Link to="/admin/returns" className="text-sm text-green-600 hover:text-green-800">Manage</Link>
          </div>
          {dashboardData?.recent_returns?.filter(r => r.status === 'PENDING').length === 0 ? (
            <p className="text-sm text-gray-500 text-center py-4">No pending returns</p>
          ) : (
            <div className="space-y-3">
              {dashboardData?.recent_returns?.filter(r => r.status === 'PENDING').slice(0, 5).map((returnReq) => (
                <div key={returnReq.id} className="flex justify-between items-center p-3 bg-yellow-50 rounded-lg">
                  <div>
                    <p className="text-sm font-medium text-gray-900">{returnReq.return_id}</p>
                    <p className="text-xs text-gray-500">{returnReq.rice_type} • {returnReq.quantity_kg} kg</p>
                  </div>
                  <Link
                    to={`/admin/returns`}
                    className="text-xs text-green-600 hover:text-green-800"
                  >
                    Process
                  </Link>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Recent Ratings */}
        <div className="bg-white shadow rounded-lg p-6">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-medium text-gray-900">Recent Ratings</h2>
            <Link to="/admin/ratings" className="text-sm text-green-600 hover:text-green-800">View all</Link>
          </div>
          <div className="space-y-3">
            {/* This would be populated from API */}
            <p className="text-sm text-gray-500 text-center py-4">Loading ratings...</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
